import{_ as c,C as d,o as t,c as u,a2 as o,b as l,w as s,a as e,E as r,a3 as i,j as p}from"./chunks/framework.B72_uj9U.js";const C=JSON.parse('{"title":"Observability","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/agentic-loop/observability.md","filePath":"research/concepts/agentic-loop/observability.md"}'),h={name:"research/concepts/agentic-loop/observability.md"};function y(g,a,m,f,b,A){const n=d("Mermaid");return t(),u("div",null,[a[5]||(a[5]=o('<h1 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Agents are black boxes without observability. Unlike traditional software where execution follows deterministic, well-understood code paths, agent behavior is fundamentally non-deterministic. The same prompt fed to the same model can produce wildly different trajectories — different tool calls, different files edited, different reasoning chains.</p><p>Observability answers two critical questions:</p><ol><li><strong>&quot;Why did the agent do that?&quot;</strong> — tracing the causal chain from input to action</li><li><strong>&quot;Where did it go wrong?&quot;</strong> — pinpointing the first divergence from correct behavior</li></ol><p>The three pillars of traditional observability — <strong>traces</strong>, <strong>metrics</strong>, and <strong>logs</strong> — all apply to agentic loops, but each requires rethinking. A trace isn&#39;t just a request/response pair; it&#39;s a multi-turn conversation with branching tool calls. Metrics aren&#39;t just latency and throughput; they include token consumption, cost, and success rate. Logs aren&#39;t just text lines; they&#39;re structured records of LLM inputs, outputs, and tool execution results.</p><p>Without observability, debugging an agent that edited the wrong file or entered an infinite loop is like debugging a distributed system with no logging — you&#39;re left guessing.</p><hr><h2 id="why-agent-observability-is-different" tabindex="-1">Why Agent Observability is Different <a class="header-anchor" href="#why-agent-observability-is-different" aria-label="Permalink to &quot;Why Agent Observability is Different&quot;">​</a></h2><h3 id="traditional-observability" tabindex="-1">Traditional Observability <a class="header-anchor" href="#traditional-observability" aria-label="Permalink to &quot;Traditional Observability&quot;">​</a></h3><p>In traditional software, observability is built around deterministic paths:</p>',11)),(t(),l(i,null,{default:s(()=>[r(n,{id:"mermaid-40",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22Request%22%5D%20--%3E%20B%5B%22Handler%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22Database%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Response%22%5D%0A"})]),fallback:s(()=>[...a[0]||(a[0]=[e(" Loading... ",-1)])]),_:1})),a[6]||(a[6]=p("p",null,"Each step is predictable. The same input produces the same output. Tracing tools like Jaeger or Zipkin instrument these paths with spans, and you get a clear picture of what happened.",-1)),a[7]||(a[7]=p("h3",{id:"agent-observability",tabindex:"-1"},[e("Agent Observability "),p("a",{class:"header-anchor",href:"#agent-observability","aria-label":'Permalink to "Agent Observability"'},"​")],-1)),a[8]||(a[8]=p("p",null,"Agent execution is fundamentally different:",-1)),(t(),l(i,null,{default:s(()=>[r(n,{id:"mermaid-50",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20U%5B%22User%20message%22%5D%20--%3E%20L1%5B%22LLM%20call%20(non-deterministic)%22%5D%0A%20%20%20%20L1%20--%3E%20TA%5B%22Tool%20call%20A%20(side%20effects)%22%5D%0A%20%20%20%20L1%20--%3E%20TB%5B%22Tool%20call%20B%20(side%20effects)%22%5D%0A%20%20%20%20TA%20--%3E%20RA%5B%22Result%20A%22%5D%0A%20%20%20%20TB%20--%3E%20RB%5B%22Result%20B%22%5D%0A%20%20%20%20RA%20%26%20RB%20--%3E%20L2%5B%22LLM%20call%20(non-deterministic%2C%5Cnconditioned%20on%20A%2BB%20results)%22%5D%0A%20%20%20%20L2%20--%3E%20TC%5B%22Tool%20call%20C%22%5D%0A%20%20%20%20TC%20--%3E%20RC%5B%22Result%20C%22%5D%0A%20%20%20%20RC%20--%3E%20L3%5B%22LLM%20call%20(non-deterministic)%22%5D%0A%20%20%20%20L3%20--%3E%20FR%5B%22Final%20response%22%5D%0A"})]),fallback:s(()=>[...a[1]||(a[1]=[e(" Loading... ",-1)])]),_:1})),a[9]||(a[9]=o(`<p>Key differences that make agent observability harder:</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Traditional Software</th><th>Agentic Loops</th></tr></thead><tbody><tr><td>Path length</td><td>Fixed or bounded</td><td>Variable (1 to 100+ turns)</td></tr><tr><td>Determinism</td><td>Same input → same output</td><td>Same input → different trajectories</td></tr><tr><td>Cost model</td><td>Compute time</td><td>Token consumption ($)</td></tr><tr><td>Side effects</td><td>Database writes</td><td>File edits, shell commands, API calls</td></tr><tr><td>Failure mode</td><td>Exceptions, timeouts</td><td>Wrong actions, hallucinations, loops</td></tr><tr><td>State</td><td>Explicit (DB, cache)</td><td>Implicit (conversation history)</td></tr></tbody></table><p>Each turn in an agentic loop produces three things that need tracing:</p><ol><li><strong>LLM call</strong>: the prompt sent, the completion received, token counts, latency</li><li><strong>Tool calls</strong>: which tools were invoked, with what arguments, and what they returned</li><li><strong>State changes</strong>: how the conversation history and external state changed</li></ol><p>Token usage directly correlates with cost — a runaway agent consuming 200k tokens on a single task is a billing incident. Model selection affects behavior in ways that are hard to predict without traces. And because the same prompt can produce wildly different trajectories, you need observability not just for debugging but for understanding the distribution of agent behavior.</p><hr><h2 id="langsmith-langchain-s-observability-platform" tabindex="-1">LangSmith (LangChain&#39;s Observability Platform) <a class="header-anchor" href="#langsmith-langchain-s-observability-platform" aria-label="Permalink to &quot;LangSmith (LangChain&#39;s Observability Platform)&quot;">​</a></h2><h3 id="overview-1" tabindex="-1">Overview <a class="header-anchor" href="#overview-1" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>LangSmith is LangChain&#39;s full-lifecycle observability platform. It covers the entire development workflow: trace, debug, evaluate, and monitor LLM applications. It is tightly integrated with LangGraph (LangChain&#39;s agent framework), making it the natural choice for teams already in that ecosystem.</p><p>LangSmith is a commercial product, but the SDK (<code>langsmith</code>) and the tracing protocol are open source. The hosted platform provides the visualization, evaluation, and monitoring features.</p><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ul><li><p><strong><code>@traceable</code> decorator</strong>: Automatic instrumentation of any Python function. Wraps the function in a span that captures inputs, outputs, latency, and errors. Supports nested calls — a traceable function calling another traceable function produces a parent-child span relationship.</p></li><li><p><strong>Run trees</strong>: Hierarchical visualization of agent execution. Each run (trace) is a tree where the root is the top-level call, and children are LLM calls, tool executions, and sub-chains. This mirrors the actual execution structure.</p></li><li><p><strong>Feedback</strong>: Attach human or automated feedback to any run. This enables building evaluation datasets from production data — mark a run as &quot;correct&quot; or &quot;incorrect&quot; and use those labels for regression testing.</p></li><li><p><strong>Datasets &amp; Evaluations</strong>: Create curated datasets of (input, expected_output) pairs and run agents against them. Supports custom evaluators, LLM-as-judge, and reference-based evaluation.</p></li><li><p><strong>Monitoring dashboards</strong>: Production metrics including latency distributions, token usage, error rates, and cost tracking over time.</p></li></ul><h3 id="tracing-example" tabindex="-1">Tracing Example <a class="header-anchor" href="#tracing-example" aria-label="Permalink to &quot;Tracing Example&quot;">​</a></h3><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> langsmith </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> traceable</span></span>
<span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> langsmith</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">run_helpers </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> get_current_run_tree</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">@traceable</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">run_type</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;chain&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> agent_loop</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">messages</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Main agent loop with full LangSmith tracing.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    while</span><span style="color:#CBA6F7;"> True</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Each LLM call is automatically traced as a child span</span></span>
<span class="line"><span style="color:#CDD6F4;">        response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">generate</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">        tool_calls </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> parse_tools</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">response</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CBA6F7;"> not</span><span style="color:#CDD6F4;"> tool_calls</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">            break</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        for</span><span style="color:#CDD6F4;"> call </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> tool_calls</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            # Tool executions are traced with inputs and outputs</span></span>
<span class="line"><span style="color:#CDD6F4;">            result </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> execute_tool</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">            messages</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">append</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">result</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#EBA0AC;font-style:italic;"> messages</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">-</span><span style="color:#FAB387;font-style:italic;">1</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">@traceable</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">run_type</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;tool&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> execute_tool</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">call</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Execute a tool call with tracing.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> call</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">name </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;bash&quot;</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> run_bash</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">args</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;font-style:italic;">command</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">])</span></span>
<span class="line"><span style="color:#CBA6F7;">    elif</span><span style="color:#CDD6F4;"> call</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">name </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;edit&quot;</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> edit_file</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">args</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;font-style:italic;">path</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">],</span><span style="color:#CDD6F4;"> call</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">args</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;font-style:italic;">content</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">])</span></span>
<span class="line"><span style="color:#CBA6F7;">    elif</span><span style="color:#CDD6F4;"> call</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">name </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;read&quot;</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> read_file</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">args</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;font-style:italic;">path</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">])</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">@traceable</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">run_type</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;llm&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> llm_generate</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">messages</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Traced LLM call capturing tokens, latency, model.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> openai</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">chat</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">completions</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">create</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;gpt-4&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        messages</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    )</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> response</span></span></code></pre></div><h3 id="what-the-trace-shows" tabindex="-1">What the Trace Shows <a class="header-anchor" href="#what-the-trace-shows" aria-label="Permalink to &quot;What the Trace Shows&quot;">​</a></h3><p>For each agent run, LangSmith captures:</p><ul><li><strong>Each LLM call</strong> with full input messages and output completion</li><li><strong>Token counts</strong> per call (prompt tokens, completion tokens, total)</li><li><strong>Latency</strong> per step (LLM call time, tool execution time, total time)</li><li><strong>Tool execution results</strong> including stdout/stderr for shell commands</li><li><strong>Error traces</strong> with full stack traces when tools or LLM calls fail</li><li><strong>Full trajectory visualization</strong> as an interactive tree</li></ul><h3 id="for-coding-agents" tabindex="-1">For Coding Agents <a class="header-anchor" href="#for-coding-agents" aria-label="Permalink to &quot;For Coding Agents&quot;">​</a></h3><p>LangSmith is particularly valuable for coding agents because:</p><ul><li>You can trace back from a bad file edit to the exact LLM call that produced it</li><li>Compare successful vs failed runs on similar coding tasks side by side</li><li>Understand why an agent searched for the wrong file or misunderstood an error</li><li>Measure how many turns different types of coding tasks require</li><li>Track cost per task type (bug fixes vs features vs refactors)</li></ul><hr><h2 id="phoenix-arize-open-source" tabindex="-1">Phoenix (Arize, Open-Source) <a class="header-anchor" href="#phoenix-arize-open-source" aria-label="Permalink to &quot;Phoenix (Arize, Open-Source)&quot;">​</a></h2><h3 id="overview-2" tabindex="-1">Overview <a class="header-anchor" href="#overview-2" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Phoenix is an open-source AI observability platform built on <strong>OpenTelemetry</strong>. Developed by Arize AI, it is vendor-agnostic and works with any LLM framework. Phoenix uses the <strong>OpenInference</strong> specification — a set of semantic conventions for AI/ML traces that extend OpenTelemetry with AI-specific attributes.</p><h3 id="key-features-1" tabindex="-1">Key Features <a class="header-anchor" href="#key-features-1" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ul><li><strong>15+ integrations</strong>: OpenAI, Anthropic, LangChain, LangGraph, CrewAI, Mastra, AutoGen, LlamaIndex, Haystack, Instructor, and more</li><li><strong>Trace visualization</strong>: Interactive trace viewer similar to LangSmith, but fully open source and self-hostable</li><li><strong>Evaluations</strong>: Built-in evaluation framework with LLM-as-judge, code-based evaluators, and custom evaluation functions</li><li><strong>Retrieval analysis</strong>: Specialized tooling for RAG-based agents — analyze retrieval quality, chunk relevance, and embedding drift</li><li><strong>Export to Pandas</strong>: Analyze traces as DataFrames for custom analysis, statistical testing, and visualization</li></ul><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><p>Phoenix follows the OpenTelemetry collector pattern:</p>`,28)),(t(),l(i,null,{default:s(()=>[r(n,{id:"mermaid-324",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20AC%5B%22Agent%20Code%22%5D%0A%20%20%20%20AC%20--%3E%20OI%5B%22OpenInference%20Instrumentor%5Cnauto-instruments%20LLM%20calls%22%5D%0A%20%20%20%20OI%20--%3E%20OT%5B%22OpenTelemetry%20SDK%5Cncreates%20spans%20with%20AI%20attributes%22%5D%0A%20%20%20%20OT%20--%3E%20EX%5B%22OTLP%20Exporter%20%E2%86%92%20Phoenix%20Collector%5Cnlocalhost%3A6006%22%5D%0A%20%20%20%20EX%20--%3E%20SU%5B%22Storage%20%2B%20UI%22%5D%0A"})]),fallback:s(()=>[...a[2]||(a[2]=[e(" Loading... ",-1)])]),_:1})),a[10]||(a[10]=o(`<p>Setup is minimal:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> phoenix</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">otel </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> register</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Connect to Phoenix collector</span></span>
<span class="line"><span style="color:#CDD6F4;">tracer_provider </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> register</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    project_name</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;coding-agent&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    endpoint</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;http://localhost:6006/v1/traces&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Automatic instrumentation — no code changes needed in your agent</span></span>
<span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> openinference</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">instrumentation</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">openai </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> OpenAIInstrumentor</span></span>
<span class="line"><span style="color:#89B4FA;">OpenAIInstrumentor</span><span style="color:#9399B2;">().</span><span style="color:#89B4FA;">instrument</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">tracer_provider</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">tracer_provider</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Now every OpenAI call is automatically traced</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># with model name, token counts, prompts, and completions</span></span></code></pre></div><p>For LangGraph agents:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> openinference</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">instrumentation</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">langchain </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> LangChainInstrumentor</span></span>
<span class="line"><span style="color:#89B4FA;">LangChainInstrumentor</span><span style="color:#9399B2;">().</span><span style="color:#89B4FA;">instrument</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">tracer_provider</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">tracer_provider</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># All LangGraph nodes, edges, and tool calls are traced</span></span></code></pre></div><h3 id="why-open-source-matters" tabindex="-1">Why Open-Source Matters <a class="header-anchor" href="#why-open-source-matters" aria-label="Permalink to &quot;Why Open-Source Matters&quot;">​</a></h3><p>For coding agents specifically, open-source observability is critical:</p><ul><li><strong>No vendor lock-in</strong>: Switch between Phoenix, Jaeger, or any OTel-compatible backend without changing instrumentation code</li><li><strong>Self-hosting for security</strong>: Coding agents see source code, credentials, and internal architecture — sending traces to a third-party SaaS raises security concerns. Self-hosted Phoenix keeps all data on your infrastructure.</li><li><strong>Extensibility</strong>: Write custom instrumentors for your own tools and frameworks</li><li><strong>Community-driven</strong>: Integrations for new frameworks are contributed by users</li><li><strong>Cost</strong>: Free to run, no per-trace pricing</li></ul><hr><h2 id="logfire-pydantic" tabindex="-1">Logfire (Pydantic) <a class="header-anchor" href="#logfire-pydantic" aria-label="Permalink to &quot;Logfire (Pydantic)&quot;">​</a></h2><h3 id="overview-3" tabindex="-1">Overview <a class="header-anchor" href="#overview-3" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Logfire is Pydantic&#39;s observability platform, built on OpenTelemetry. It has deep integration with PydanticAI (Pydantic&#39;s agent framework) and provides real-time debugging capabilities that are particularly useful during agent development.</p><h3 id="key-features-2" tabindex="-1">Key Features <a class="header-anchor" href="#key-features-2" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ul><li><strong>Live view</strong>: See agent execution in real time as it happens — each LLM call, tool execution, and decision appears as it occurs</li><li><strong>Structured data</strong>: Pydantic models are automatically serialized and displayed in traces. Since PydanticAI uses Pydantic models for tool parameters and results, this means rich, typed trace data</li><li><strong>Cost tracking</strong>: Automatic token usage and cost calculation per operation, with support for different model pricing tiers</li><li><strong>SQL queries</strong>: Query your traces using SQL — powerful for custom analysis like &quot;show me all runs where token usage exceeded 10k&quot; or &quot;find all tool failures in the last hour&quot;</li><li><strong>Dashboards</strong>: Customizable monitoring dashboards with alerting</li></ul><h3 id="pydanticai-integration" tabindex="-1">PydanticAI Integration <a class="header-anchor" href="#pydanticai-integration" aria-label="Permalink to &quot;PydanticAI Integration&quot;">​</a></h3><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> pydantic_ai </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Agent</span></span>
<span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> logfire</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># One-time setup</span></span>
<span class="line"><span style="color:#CDD6F4;">logfire</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">configure</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CDD6F4;">logfire</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">instrument_pydantic_ai</span><span style="color:#9399B2;">()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Define agent as normal</span></span>
<span class="line"><span style="color:#CDD6F4;">agent </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Agent</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;openai:gpt-4&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    system_prompt</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;You are a coding assistant. Fix bugs in Python code.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run the agent — all internals are automatically traced</span></span>
<span class="line"><span style="color:#CDD6F4;">result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> agent</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Fix the NullPointerException in auth.py&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Logfire captures:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># - System prompt content</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># - User message</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># - Each LLM call (model, tokens, latency, cost)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># - Tool calls and results</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># - Final response</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># - Total cost for the entire run</span></span></code></pre></div><h3 id="querying-traces-with-sql" tabindex="-1">Querying Traces with SQL <a class="header-anchor" href="#querying-traces-with-sql" aria-label="Permalink to &quot;Querying Traces with SQL&quot;">​</a></h3><p>One of Logfire&#39;s unique features is SQL-based trace analysis:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">-- Find the most expensive agent runs</span></span>
<span class="line"><span style="color:#CBA6F7;">SELECT</span></span>
<span class="line"><span style="color:#CDD6F4;">    span_name,</span></span>
<span class="line"><span style="color:#CDD6F4;">    attributes</span><span style="color:#94E2D5;">-&gt;&gt;</span><span style="color:#A6E3A1;">&#39;total_tokens&#39;</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> tokens,</span></span>
<span class="line"><span style="color:#CDD6F4;">    attributes</span><span style="color:#94E2D5;">-&gt;&gt;</span><span style="color:#A6E3A1;">&#39;cost_usd&#39;</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> cost,</span></span>
<span class="line"><span style="color:#CDD6F4;">    duration_ms</span></span>
<span class="line"><span style="color:#CBA6F7;">FROM</span><span style="color:#CDD6F4;"> spans</span></span>
<span class="line"><span style="color:#CBA6F7;">WHERE</span><span style="color:#CDD6F4;"> span_name </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &#39;agent_run&#39;</span></span>
<span class="line"><span style="color:#CBA6F7;">ORDER BY</span><span style="color:#CDD6F4;"> cost </span><span style="color:#CBA6F7;">DESC</span></span>
<span class="line"><span style="color:#CBA6F7;">LIMIT</span><span style="color:#FAB387;"> 10</span><span style="color:#CDD6F4;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">-- Find runs where the agent got stuck in a loop</span></span>
<span class="line"><span style="color:#CBA6F7;">SELECT</span><span style="color:#CDD6F4;"> trace_id, </span><span style="color:#89B4FA;font-style:italic;">COUNT</span><span style="color:#CDD6F4;">(</span><span style="color:#94E2D5;">*</span><span style="color:#CDD6F4;">) </span><span style="color:#CBA6F7;">as</span><span style="color:#CDD6F4;"> turn_count</span></span>
<span class="line"><span style="color:#CBA6F7;">FROM</span><span style="color:#CDD6F4;"> spans</span></span>
<span class="line"><span style="color:#CBA6F7;">WHERE</span><span style="color:#CDD6F4;"> span_name </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &#39;llm_call&#39;</span></span>
<span class="line"><span style="color:#CBA6F7;">GROUP BY</span><span style="color:#CDD6F4;"> trace_id</span></span>
<span class="line"><span style="color:#CBA6F7;">HAVING</span><span style="color:#89B4FA;font-style:italic;"> COUNT</span><span style="color:#CDD6F4;">(</span><span style="color:#94E2D5;">*</span><span style="color:#CDD6F4;">) </span><span style="color:#94E2D5;">&gt;</span><span style="color:#FAB387;"> 20</span><span style="color:#CDD6F4;">;</span></span></code></pre></div><hr><h2 id="opentelemetry-for-agents" tabindex="-1">OpenTelemetry for Agents <a class="header-anchor" href="#opentelemetry-for-agents" aria-label="Permalink to &quot;OpenTelemetry for Agents&quot;">​</a></h2><h3 id="the-standard" tabindex="-1">The Standard <a class="header-anchor" href="#the-standard" aria-label="Permalink to &quot;The Standard&quot;">​</a></h3><p>OpenTelemetry (OTel) is the industry standard for observability. It provides a vendor-neutral specification for traces, metrics, and logs. Both Phoenix and Logfire are built on OTel, which means traces from either can be exported to any OTel-compatible backend (Jaeger, Grafana Tempo, Datadog, etc.).</p><p>For agents, OTel provides the foundational primitives:</p><ul><li><strong>Trace</strong>: A complete agent run from start to finish</li><li><strong>Span</strong>: A single operation within the trace (LLM call, tool execution)</li><li><strong>Attributes</strong>: Key-value metadata on spans (model name, token count)</li><li><strong>Events</strong>: Point-in-time occurrences within a span (errors, state changes)</li><li><strong>Links</strong>: Connections between spans across traces (agent-to-agent calls)</li></ul><h3 id="agent-specific-spans" tabindex="-1">Agent-Specific Spans <a class="header-anchor" href="#agent-specific-spans" aria-label="Permalink to &quot;Agent-Specific Spans&quot;">​</a></h3><p>A typical coding agent trace looks like this:</p>`,26)),(t(),l(i,null,{default:s(()=>[r(n,{id:"mermaid-463",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20TR%5B%22trace%3A%20agent_run%5Cnid%3Dabc123%20%7C%20task%3Dfix%20auth%20bug%22%5D%0A%20%20%20%20TR%20--%3E%20LLM1%5B%22span%3A%20llm_call%5Cnmodel%3Dgpt-4%20%7C%20tokens_in%3D1500%20%7C%20tokens_out%3D200%5Cnlatency_ms%3D1840%20%7C%20cost_usd%3D0.057%22%5D%0A%20%20%20%20TR%20--%3E%20TOOL1%5B%22span%3A%20tool_execution%5Cntool%3Dbash%20%7C%20command%3Dgrep%20-r%20NullPointer%20src%2F%5Cnduration_ms%3D340%20%7C%20exit_code%3D0%22%5D%0A%20%20%20%20TOOL1%20--%3E%20SUB%5B%22span%3A%20subprocess%5Cncmd%3Dgrep%20-r%20NullPointer%20src%2F%5Cnstdout%3Dsrc%2Fauth.py%3A42%3A%20raise%20NullPointer...%5Cnexit_code%3D0%22%5D%0A%20%20%20%20TR%20--%3E%20LLM2%5B%22span%3A%20llm_call%5Cnmodel%3Dgpt-4%20%7C%20tokens_in%3D2100%20%7C%20tokens_out%3D150%5Cncost_usd%3D0.072%22%5D%0A%20%20%20%20TR%20--%3E%20TOOL2%5B%22span%3A%20tool_execution%5Cntool%3Dedit%20%7C%20file%3Dsrc%2Fauth.py%5Cnlines_changed%3D3%20%7C%20duration_ms%3D12%22%5D%0A%20%20%20%20TR%20--%3E%20LLM3%5B%22span%3A%20llm_call%5Cnmodel%3Dgpt-4%20%7C%20tokens_in%3D2400%20%7C%20tokens_out%3D50%5Cncost_usd%3D0.075%22%5D%0A"})]),fallback:s(()=>[...a[3]||(a[3]=[e(" Loading... ",-1)])]),_:1})),a[11]||(a[11]=o(`<h3 id="openinference-specification" tabindex="-1">OpenInference Specification <a class="header-anchor" href="#openinference-specification" aria-label="Permalink to &quot;OpenInference Specification&quot;">​</a></h3><p>OpenInference is a set of semantic conventions that standardize how AI/ML traces are recorded. It defines:</p><ul><li><strong>Span kinds</strong>: <code>LLM</code>, <code>CHAIN</code>, <code>TOOL</code>, <code>AGENT</code>, <code>RETRIEVER</code>, <code>EMBEDDING</code></li><li><strong>Span attributes</strong>: <code>llm.model_name</code>, <code>llm.token_count.prompt</code>, <code>llm.token_count.completion</code>, <code>llm.input_messages</code>, <code>llm.output_messages</code></li><li><strong>Tool attributes</strong>: <code>tool.name</code>, <code>tool.parameters</code>, <code>tool.description</code></li></ul><p>This standardization means traces from different frameworks (LangChain, CrewAI, PydanticAI) can be visualized and analyzed in the same way.</p><hr><h2 id="trace-formats-and-visualization" tabindex="-1">Trace Formats and Visualization <a class="header-anchor" href="#trace-formats-and-visualization" aria-label="Permalink to &quot;Trace Formats and Visualization&quot;">​</a></h2><h3 id="hierarchical-traces" tabindex="-1">Hierarchical Traces <a class="header-anchor" href="#hierarchical-traces" aria-label="Permalink to &quot;Hierarchical Traces&quot;">​</a></h3><p>The most natural way to represent agent execution is as a tree:</p><ul><li><strong>Root span</strong>: The entire agent run (user message → final response)</li><li><strong>Child spans (level 1)</strong>: Individual turns (LLM call + resulting tool calls)</li><li><strong>Child spans (level 2)</strong>: Individual tool executions within a turn</li><li><strong>Child spans (level 3)</strong>: Sub-operations within tools (subprocesses, API calls)</li></ul><p>This mirrors the actual execution structure and is visualized as flame charts or collapsible tree views in tools like LangSmith, Phoenix, and Logfire.</p><h3 id="waterfall-view" tabindex="-1">Waterfall View <a class="header-anchor" href="#waterfall-view" aria-label="Permalink to &quot;Waterfall View&quot;">​</a></h3><p>The waterfall view shows time on the x-axis, making it easy to see parallelism and bottlenecks:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Time →</span></span>
<span class="line"><span>|===== LLM Call 1 (1.8s) =====|</span></span>
<span class="line"><span>                                |== Tool: grep (0.3s) ==|</span></span>
<span class="line"><span>                                |=== Tool: read (0.1s) ==|</span></span>
<span class="line"><span>                                                          |======= LLM Call 2 (2.1s) =======|</span></span>
<span class="line"><span>                                                                                              |== Tool: edit (0.01s) =|</span></span>
<span class="line"><span>                                                                                              |==== Tool: bash (3.2s) ====|</span></span>
<span class="line"><span>                                                                                                                          |=== LLM Call 3 (0.9s) ===|</span></span></code></pre></div><p>This view immediately reveals that:</p><ul><li>LLM calls dominate wall-clock time</li><li>Tool executions (except bash/tests) are fast</li><li>There&#39;s no parallelism — everything is sequential</li></ul><h3 id="trajectory-replay" tabindex="-1">Trajectory Replay <a class="header-anchor" href="#trajectory-replay" aria-label="Permalink to &quot;Trajectory Replay&quot;">​</a></h3><p>Several agent frameworks support trajectory replay — recording the complete execution history and replaying it to reproduce behavior:</p><ul><li><p><strong>mini-SWE-agent</strong>: Trajectory files are JSON records of every action and observation. The trajectory IS the complete trace — human-readable and directly replayable.</p></li><li><p><strong>OpenHands</strong>: The EventStream records every event (actions, observations, state changes) and can be replayed to reproduce the exact agent behavior.</p></li><li><p><strong>Codex</strong>: JSONL rollout files record the full conversation and enable resuming from any point in the execution.</p></li><li><p><strong>Claude Code</strong>: Checkpoints capture both conversation state and code state, enabling rollback to any previous point.</p></li><li><p><strong>LangGraph</strong>: Time-travel debugging lets you inspect and modify state at any node in the graph, then resume execution from that point.</p></li></ul><hr><h2 id="what-to-measure" tabindex="-1">What to Measure <a class="header-anchor" href="#what-to-measure" aria-label="Permalink to &quot;What to Measure&quot;">​</a></h2><h3 id="per-turn-metrics" tabindex="-1">Per-Turn Metrics <a class="header-anchor" href="#per-turn-metrics" aria-label="Permalink to &quot;Per-Turn Metrics&quot;">​</a></h3><p>Each turn in the agentic loop should track:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th><th>Why It Matters</th></tr></thead><tbody><tr><td>Latency</td><td>Time from sending prompt to receiving completion</td><td>User experience, timeout detection</td></tr><tr><td>Tokens in</td><td>Prompt token count</td><td>Cost tracking, context window usage</td></tr><tr><td>Tokens out</td><td>Completion token count</td><td>Cost tracking, verbosity detection</td></tr><tr><td>Cost</td><td>Calculated from tokens × model pricing</td><td>Budget management</td></tr><tr><td>Tool success rate</td><td>% of tool calls that succeed</td><td>Reliability measurement</td></tr><tr><td>Tool latency</td><td>Time in tool execution vs LLM</td><td>Bottleneck identification</td></tr><tr><td>Context utilization</td><td>% of context window used</td><td>Overflow prediction</td></tr></tbody></table><h3 id="per-session-metrics" tabindex="-1">Per-Session Metrics <a class="header-anchor" href="#per-session-metrics" aria-label="Permalink to &quot;Per-Session Metrics&quot;">​</a></h3><p>Aggregate across all turns in a single agent session:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th><th>Typical Range</th></tr></thead><tbody><tr><td>Total turns</td><td>Number of LLM calls to complete task</td><td>3–50</td></tr><tr><td>Total cost</td><td>Sum of all LLM call costs</td><td>$0.01–$5.00</td></tr><tr><td>Wall-clock time</td><td>Total time from start to finish</td><td>10s–10min</td></tr><tr><td>Tool distribution</td><td>Which tools used and how often</td><td>Varies by task</td></tr><tr><td>Errors encountered</td><td>Count and types of errors</td><td>0–10</td></tr><tr><td>Stuck events</td><td>Times agent repeated actions</td><td>0 (ideally)</td></tr><tr><td>Context resets</td><td>Times context was truncated/summarized</td><td>0–3</td></tr></tbody></table><h3 id="aggregate-metrics-fleet-level" tabindex="-1">Aggregate Metrics (Fleet-Level) <a class="header-anchor" href="#aggregate-metrics-fleet-level" aria-label="Permalink to &quot;Aggregate Metrics (Fleet-Level)&quot;">​</a></h3><p>When running agents at scale:</p><ul><li><strong>Success rate by task type</strong>: Bug fixes might succeed 70%, new features 40%</li><li><strong>Average cost per task</strong>: Understand unit economics</li><li><strong>P50/P95/P99 latency</strong>: Tail latency reveals worst-case behavior</li><li><strong>Error rate by category</strong>: Tool failures, hallucinations, timeouts</li><li><strong>Model comparison</strong>: Same tasks run on different models — cost vs quality</li><li><strong>Turn count distribution</strong>: Bimodal? (easy tasks vs hard tasks)</li></ul><hr><h2 id="debugging-agent-failures" tabindex="-1">Debugging Agent Failures <a class="header-anchor" href="#debugging-agent-failures" aria-label="Permalink to &quot;Debugging Agent Failures&quot;">​</a></h2><h3 id="common-failure-modes" tabindex="-1">Common Failure Modes <a class="header-anchor" href="#common-failure-modes" aria-label="Permalink to &quot;Common Failure Modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Failure Mode</th><th>Root Cause</th><th>How to Debug</th></tr></thead><tbody><tr><td>1</td><td>Wrong file edited</td><td>Bad search results or hallucinated path</td><td>Trace the search tool calls that led to file selection</td></tr><tr><td>2</td><td>Infinite loop</td><td>Agent repeating the same actions</td><td>Check trace for repeated tool calls with identical args</td></tr><tr><td>3</td><td>Context overflow</td><td>Too much data accumulated in history</td><td>Monitor token counts per turn, find the spike</td></tr><tr><td>4</td><td>Tool failure cascade</td><td>One tool failure causes subsequent failures</td><td>Check error propagation: does the agent handle errors?</td></tr><tr><td>5</td><td>Model hallucination</td><td>Model generates non-existent APIs/files</td><td>Compare model output to the actual context it received</td></tr><tr><td>6</td><td>Premature termination</td><td>Agent declares success before task is done</td><td>Check final LLM call — did it misinterpret results?</td></tr><tr><td>7</td><td>Cost blowup</td><td>Agent takes too many turns or uses too much context</td><td>Track cumulative cost curve — where does it spike?</td></tr></tbody></table><h3 id="debugging-workflow" tabindex="-1">Debugging Workflow <a class="header-anchor" href="#debugging-workflow" aria-label="Permalink to &quot;Debugging Workflow&quot;">​</a></h3><p>A systematic approach to debugging agent failures:</p>`,35)),(t(),l(i,null,{default:s(()=>[r(n,{id:"mermaid-958",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20S1%5B%221.%20Identify%20the%20failed%20task%5CnExpected%20outcome%20vs%20actual%20outcome%3F%22%5D%0A%20%20%20%20S2%5B%222.%20Load%20the%20trace%20%2F%20trajectory%5CnLangSmith%20%2F%20Phoenix%20%2F%20Logfire%20%2F%20trajectory%20file%22%5D%0A%20%20%20%20S3%5B%223.%20Find%20the%20first%20wrong%20step%5CnScan%20trace%20chronologically%22%5D%0A%20%20%20%20S4%5B%224.%20Examine%20the%20model's%20input%20at%20that%20step%5CnMessages%20seen%20%7C%20Tool%20results%20in%20context%20%7C%20Info%20present%3F%22%5D%0A%20%20%20%20S5%5B%225.%20Diagnose%20the%20root%20cause%22%5D%0A%20%20%20%20S6%5B%226.%20Apply%20the%20fix%22%5D%0A%20%20%20%20D1%5B%22Info%20present%20but%20ignored%20%E2%86%92%20prompt%20issue%22%5D%0A%20%20%20%20D2%5B%22Info%20missing%20%E2%86%92%20tool%2Fsearch%20issue%22%5D%0A%20%20%20%20D3%5B%22Info%20wrong%20%E2%86%92%20tool%20execution%20issue%22%5D%0A%20%20%20%20D4%5B%22Hallucinated%20despite%20good%20input%20%E2%86%92%20model%20limitation%22%5D%0A%20%20%20%20F1%5B%22Improve%20system%20prompt%20or%20few-shot%20examples%22%5D%0A%20%20%20%20F2%5B%22Fix%20tool%20implementation%20or%20add%20new%20tool%5Cnor%20improve%20search%20strategy%22%5D%0A%20%20%20%20F3%5B%22Try%20different%20model%20or%20add%20guardrails%22%5D%0A%20%20%20%20F4%5B%22Improve%20loop%20termination%20logic%22%5D%0A%20%20%20%20S1%20--%3E%20S2%20--%3E%20S3%20--%3E%20S4%20--%3E%20S5%20--%3E%20S6%0A%20%20%20%20S5%20--%3E%20D1%20%26%20D2%20%26%20D3%20%26%20D4%0A%20%20%20%20D1%20--%3E%20F1%0A%20%20%20%20D2%20%26%20D3%20--%3E%20F2%0A%20%20%20%20D4%20--%3E%20F3%0A%20%20%20%20S6%20--%3E%20F1%20%26%20F2%20%26%20F3%20%26%20F4%0A"})]),fallback:s(()=>[...a[4]||(a[4]=[e(" Loading... ",-1)])]),_:1})),a[12]||(a[12]=o(`<h3 id="agent-specific-debug-tools" tabindex="-1">Agent-Specific Debug Tools <a class="header-anchor" href="#agent-specific-debug-tools" aria-label="Permalink to &quot;Agent-Specific Debug Tools&quot;">​</a></h3><p>Each major agent framework provides its own debugging primitives:</p><ul><li><p><strong>mini-SWE-agent</strong>: Trajectory files are plain JSON — grep through them, load into Python, or view in any JSON viewer. Simple and effective.</p></li><li><p><strong>OpenHands</strong>: EventStream replay lets you step through events one by one. The web UI provides a visual timeline of agent actions.</p></li><li><p><strong>Codex</strong>: JSONL rollout files record everything. The <code>--resume</code> flag lets you restart from a checkpoint after fixing an issue.</p></li><li><p><strong>Claude Code</strong>: Conversation checkpoints include both the message history and the state of the working directory. Roll back to any checkpoint.</p></li><li><p><strong>LangGraph</strong>: Time-travel debugging is built into the framework. Inspect the state at any node, modify it, and resume execution from that point. This is uniquely powerful for graph-based agents.</p></li></ul><hr><h2 id="comparison-table" tabindex="-1">Comparison Table <a class="header-anchor" href="#comparison-table" aria-label="Permalink to &quot;Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>LangSmith</th><th>Phoenix (Arize)</th><th>Logfire (Pydantic)</th></tr></thead><tbody><tr><td><strong>Open Source</strong></td><td>SDK only</td><td>Fully open source</td><td>No</td></tr><tr><td><strong>OTel-Based</strong></td><td>No (proprietary)</td><td>Yes</td><td>Yes</td></tr><tr><td><strong>Multi-Framework</strong></td><td>LangChain/LangGraph</td><td>15+ frameworks</td><td>PydanticAI focus</td></tr><tr><td><strong>Self-Hostable</strong></td><td>No (SaaS only)</td><td>Yes</td><td>No (SaaS only)</td></tr><tr><td><strong>Real-Time View</strong></td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td><strong>Cost Tracking</strong></td><td>Yes</td><td>Via attributes</td><td>Built-in</td></tr><tr><td><strong>SQL Queries</strong></td><td>No</td><td>Export to Pandas</td><td>Yes (native SQL)</td></tr><tr><td><strong>Evaluations</strong></td><td>Yes (built-in)</td><td>Yes (built-in)</td><td>Via integrations</td></tr><tr><td><strong>Pricing</strong></td><td>Free tier + paid</td><td>Free (self-host)</td><td>Free tier + paid</td></tr><tr><td><strong>Best For</strong></td><td>LangChain teams</td><td>Vendor-agnostic needs</td><td>PydanticAI teams</td></tr></tbody></table><h3 id="choosing-the-right-tool" tabindex="-1">Choosing the Right Tool <a class="header-anchor" href="#choosing-the-right-tool" aria-label="Permalink to &quot;Choosing the Right Tool&quot;">​</a></h3><ul><li><strong>Already using LangGraph?</strong> → LangSmith is the path of least resistance</li><li><strong>Need open-source / self-hosted?</strong> → Phoenix is the clear choice</li><li><strong>Using PydanticAI?</strong> → Logfire provides the tightest integration</li><li><strong>Want vendor flexibility?</strong> → Phoenix (OTel-based, swap backends freely)</li><li><strong>Enterprise with compliance needs?</strong> → Phoenix self-hosted or Logfire with data residency guarantees</li></ul><hr><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="_1-instrument-from-day-one" tabindex="-1">1. Instrument from Day One <a class="header-anchor" href="#_1-instrument-from-day-one" aria-label="Permalink to &quot;1. Instrument from Day One&quot;">​</a></h3><p>Adding observability after the fact is painful. Start with tracing enabled from the first prototype. Even a simple <code>print()</code> trace is better than nothing, but structured tracing (OTel spans) is only marginally more effort and vastly more useful.</p><h3 id="_2-track-cost-per-turn-not-just-per-session" tabindex="-1">2. Track Cost per Turn, Not Just per Session <a class="header-anchor" href="#_2-track-cost-per-turn-not-just-per-session" aria-label="Permalink to &quot;2. Track Cost per Turn, Not Just per Session&quot;">​</a></h3><p>Session-level cost hides important information. A 20-turn session that costs $2 might have 18 cheap turns and 2 expensive ones. Per-turn cost tracking reveals which operations are expensive and where optimization matters.</p><h3 id="_3-save-full-trajectories" tabindex="-1">3. Save Full Trajectories <a class="header-anchor" href="#_3-save-full-trajectories" aria-label="Permalink to &quot;3. Save Full Trajectories&quot;">​</a></h3><p>Don&#39;t just save summaries — save the complete trace with all inputs, outputs, and tool results. Disk is cheap. When debugging a failure months later, you&#39;ll need the full context. Trajectories are also essential for building evaluation datasets.</p><h3 id="_4-compare-successful-vs-failed-runs" tabindex="-1">4. Compare Successful vs Failed Runs <a class="header-anchor" href="#_4-compare-successful-vs-failed-runs" aria-label="Permalink to &quot;4. Compare Successful vs Failed Runs&quot;">​</a></h3><p>The most powerful debugging technique is diff-based: take a successful run and a failed run on similar tasks, and compare them step by step. Where do they diverge? This immediately reveals the root cause.</p><h3 id="_5-alert-on-anomalous-patterns" tabindex="-1">5. Alert on Anomalous Patterns <a class="header-anchor" href="#_5-alert-on-anomalous-patterns" aria-label="Permalink to &quot;5. Alert on Anomalous Patterns&quot;">​</a></h3><p>Set up alerts for:</p><ul><li><strong>Stuck loops</strong>: More than N turns without progress</li><li><strong>Cost spikes</strong>: Single run exceeding cost threshold</li><li><strong>High error rates</strong>: Tool failure rate above baseline</li><li><strong>Latency outliers</strong>: P99 latency exceeding SLA</li></ul><h3 id="_6-use-structured-logging" tabindex="-1">6. Use Structured Logging <a class="header-anchor" href="#_6-use-structured-logging" aria-label="Permalink to &quot;6. Use Structured Logging&quot;">​</a></h3><p>Replace <code>print(f&quot;Tool result: {result}&quot;)</code> with structured spans:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">with</span><span style="color:#CDD6F4;"> tracer</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">start_as_current_span</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;tool_execution&quot;</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> span</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    span</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">set_attribute</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;tool.name&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> tool_name</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    span</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">set_attribute</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;tool.args&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> json</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">dumps</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">args</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#CDD6F4;">    result </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> execute</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tool_name</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> args</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    span</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">set_attribute</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;tool.result_length&quot;</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;font-style:italic;">str</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">result</span><span style="color:#9399B2;">)))</span></span>
<span class="line"><span style="color:#CDD6F4;">    span</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">set_attribute</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;tool.success&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">success</span><span style="color:#9399B2;">)</span></span></code></pre></div><h3 id="_7-keep-trace-data-for-evaluation-and-fine-tuning" tabindex="-1">7. Keep Trace Data for Evaluation and Fine-Tuning <a class="header-anchor" href="#_7-keep-trace-data-for-evaluation-and-fine-tuning" aria-label="Permalink to &quot;7. Keep Trace Data for Evaluation and Fine-Tuning&quot;">​</a></h3><p>Production traces are the best source of training data. Successful runs become positive examples. Failed runs (once diagnosed) become negative examples or test cases. Over time, your trace database becomes your most valuable asset for improving agent quality.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Observability is not optional for agentic systems. The non-deterministic, multi-turn, tool-using nature of agents makes them fundamentally harder to debug than traditional software. The ecosystem is converging on OpenTelemetry as the standard, with Phoenix (open-source) and Logfire (commercial) leading the OTel-native approach, and LangSmith providing deep integration for the LangChain ecosystem. Regardless of which tool you choose, the principles are the same: trace everything, measure cost, save trajectories, and build your debugging workflow around comparing successful and failed runs.</p>`,29))])}const B=c(h,[["render",y]]);export{C as __pageData,B as default};
